sql:
SELECT message_id, article_id, poster_id
FROM farewell_messages
WHERE message_id = 1;

SELECT u.username, fm.message_id, fm.poster_id 
FROM users u
JOIN farewell_messages fm ON u.user_id = fm.poster_id;

SELECT user_id, COUNT(*) AS view_count 
FROM article_views
GROUP BY user_id;

SELECT COUNT(*) AS likes_count
FROM message_likes
WHERE user_id = 1;
